import { mkdir, writeFile } from "node:fs/promises";
import { createHash } from "node:crypto";
import path from "node:path";
import { createComparisonReport, formatComparisonMarkdown, renderComparisonHtml } from "./compare.js";
import { formatDoctorReport } from "./doctor.js";
function relativePath(from, target) {
    const relative = path.relative(from, target).replaceAll("\\", "/");
    return relative && !relative.startsWith("..") ? relative : target;
}
function markdownCode(value) {
    return `\`${String(value).replaceAll("`", "\\`")}\``;
}
function sha256(source) {
    return createHash("sha256").update(source).digest("hex");
}
function fileList(files, directory) {
    return Object.entries(files)
        .map(([label, filePath]) => `- ${label}: ${markdownCode(relativePath(directory, filePath))}`)
        .join("\n");
}
function topRecommendations(report) {
    if (!report.recommendations.length)
        return "- No immediate documentation actions.";
    return report.recommendations
        .slice(0, 5)
        .map((recommendation) => `- ${recommendation.message}${recommendation.command ? ` (${markdownCode(recommendation.command)})` : ""}`)
        .join("\n");
}
function privacyNotice(ai) {
    return ai === true
        ? "Generated with optional AI refinement. Project metadata may have been sent to the configured Gemini API."
        : "Generated locally by readme-forge. No project data was uploaded.";
}
function renderReviewIndex(result, report, ai) {
    const comparison = result.comparison;
    const qualityChange = comparison.improvement >= 0 ? `+${comparison.improvement}` : String(comparison.improvement);
    return `# readme-forge Review Bundle

This folder contains a local README review bundle generated by \`readme-forge review\`.

## Summary

| Field | Value |
| --- | --- |
| Project | ${comparison.project.name} |
| README | ${markdownCode(comparison.project.readmePath)} |
| Current score | ${comparison.current.quality.score}/${comparison.current.quality.maxScore} (${comparison.current.quality.percentage}%) |
| Generated score | ${comparison.generated.quality.score}/${comparison.generated.quality.maxScore} (${comparison.generated.quality.percentage}%) |
| Quality change | ${qualityChange} percentage points |
| Doctor status | ${report.ok ? "ready" : "needs follow-up"} |

## Files

${fileList(result.files, result.directory)}

## Suggested Next Actions

${topRecommendations(report)}

## Review Locally

\`\`\`bash
readme-forge . --diff
readme-forge compare . --output readme-forge-review/compare.html
readme-forge apply . --dry-run
readme-forge apply .
\`\`\`

${privacyNotice(ai)}
`;
}
function renderPrComment(comparison, report, ai) {
    const qualityChange = comparison.improvement >= 0 ? `+${comparison.improvement}` : String(comparison.improvement);
    return `## README Review

readme-forge generated a README review bundle for this repository.

| Metric | Value |
| --- | --- |
| Current score | ${comparison.current.quality.score}/${comparison.current.quality.maxScore} (${comparison.current.quality.percentage}%) |
| Generated score | ${comparison.generated.quality.score}/${comparison.generated.quality.maxScore} (${comparison.generated.quality.percentage}%) |
| Quality change | ${qualityChange} percentage points |
| Line changes | +${comparison.diff.additions} / -${comparison.diff.removals} |

### Recommended Next Actions

${topRecommendations(report)}

### Review Commands

\`\`\`bash
readme-forge review .
readme-forge . --diff
readme-forge apply . --dry-run
\`\`\`

${privacyNotice(ai)}`;
}
function createSummary(input, comparison, files) {
    return {
        project: comparison.project,
        readme: {
            changed: comparison.changed,
            currentScore: comparison.current.quality.percentage,
            generatedScore: comparison.generated.quality.percentage,
            generatedWithAi: input.ai === true,
            improvement: comparison.improvement,
            profile: comparison.profile
        },
        diff: comparison.diff,
        hashes: {
            currentReadmeSha256: sha256(input.existing),
            generatedReadmeSha256: sha256(input.generated)
        },
        doctor: {
            ok: input.doctorReport.ok,
            recommendations: input.doctorReport.recommendations.map((recommendation) => ({
                id: recommendation.id,
                message: recommendation.message,
                command: recommendation.command
            }))
        },
        files: Object.fromEntries(Object.entries(files).map(([key, filePath]) => [key, relativePath(input.root, filePath)]))
    };
}
export async function writeReviewBundle(input) {
    const directory = path.resolve(input.outputDir);
    const files = {
        indexMarkdown: path.join(directory, "README.md"),
        generatedReadme: path.join(directory, "README.generated.md"),
        compareHtml: path.join(directory, "compare.html"),
        compareMarkdown: path.join(directory, "compare.md"),
        doctorMarkdown: path.join(directory, "doctor.md"),
        prComment: path.join(directory, "PR_COMMENT.md"),
        summaryJson: path.join(directory, "summary.json")
    };
    const comparison = createComparisonReport({
        ai: input.ai,
        existing: input.existing,
        facts: input.doctorReport.facts,
        generated: input.generated,
        profile: input.doctorReport.readme.quality.profile,
        readmePath: input.readmePath,
        root: input.root
    });
    const result = { comparison, directory, files };
    const summary = createSummary(input, comparison, files);
    await mkdir(directory, { recursive: true });
    await writeFile(files.generatedReadme, `${input.generated.trim()}\n`, "utf8");
    await writeFile(files.compareHtml, renderComparisonHtml({
        existing: input.existing,
        ai: input.ai,
        facts: input.doctorReport.facts,
        generated: input.generated,
        profile: input.doctorReport.readme.quality.profile,
        readmePath: input.readmePath,
        root: input.root
    }), "utf8");
    await writeFile(files.compareMarkdown, `${formatComparisonMarkdown(comparison).trim()}\n`, "utf8");
    await writeFile(files.doctorMarkdown, `${formatDoctorReport(input.doctorReport).trim()}\n`, "utf8");
    await writeFile(files.prComment, `${renderPrComment(comparison, input.doctorReport, input.ai).trim()}\n`, "utf8");
    await writeFile(files.summaryJson, `${JSON.stringify(summary, null, 2)}\n`, "utf8");
    await writeFile(files.indexMarkdown, `${renderReviewIndex(result, input.doctorReport, input.ai).trim()}\n`, "utf8");
    return result;
}
